// 3. Implement on entitlementHandler
func (h *entitlementHandler) GetCustomerEntitlementValue() GetCustomerEntitlementValueHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params GetCustomerEntitlementValueHandlerParams) (GetCustomerEntitlementValueHandlerRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return GetCustomerEntitlementValueHandlerRequest{}, err
			}
			cus, err := h.customerService.GetCustomer(ctx, customer.GetCustomerInput{
				CustomerIDOrKey: &customer.CustomerIDOrKey{Namespace: ns, IDOrKey: params.CustomerIDOrKey},
			})
			if err != nil {
				return GetCustomerEntitlementValueHandlerRequest{}, err
			}
			if cus != nil && cus.IsDeleted() {
				return GetCustomerEntitlementValueHandlerRequest{}, models.NewGenericPreConditionFailedError(
					fmt.Errorf("customer is deleted [namespace=%s customer.id=%s]", cus.Namespace, cus.ID),
				)
			}
			return GetCustomerEntitlementValueHandlerRequest{
				CustomerIDOrKey:           cus.ID,
				EntitlementIdOrFeatureKey: params.EntitlementIdOrFeatureKey,
				Namespace:                 ns,
			}, nil
		},
		func(ctx context.Context, req GetCustomerEntitlementValueHandlerRequest) (GetCustomerEntitlementValueHandlerResponse, error) {
			v, err := h.connector.GetEntitlementValue(ctx, req.Namespace, req.CustomerIDOrKey, req.EntitlementIdOrFeatureKey, clock.Now())
			if err != nil {
				return nil, err
			}
			// map v to api.EntitlementValue
			return mapEntitlementValueToAPI(v), nil
		},
		commonhttp.JSONResponseEncoder[GetCustomerEntitlementValueHandlerResponse],
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("getCustomerEntitlementValueV2"),
			httptransport.WithErrorEncoder(getErrorEncoder()),
		)...,
	)
}
